import React, { useState, useEffect, useRef } from 'react';

const MapPicker = ({ onLocationSelect, initialLat = 27.7172, initialLng = 85.3240 }) => {
  const mapRef = useRef(null);
  const [map, setMap] = useState(null);
  const [marker, setMarker] = useState(null);
  const [selectedLocation, setSelectedLocation] = useState({
    lat: initialLat,
    lng: initialLng
  });

  useEffect(() => {
    // Load Google Maps script
    if (!window.google) {
      const script = document.createElement('script');
      script.src = `https://maps.googleapis.com/maps/api/js?key=${process.env.REACT_APP_GOOGLE_MAPS_API_KEY}&libraries=places`;
      script.async = true;
      script.defer = true;
      script.onload = initializeMap;
      document.head.appendChild(script);
    } else {
      initializeMap();
    }
  }, []);

  useEffect(() => {
    if (map && marker) {
      marker.setPosition({ lat: initialLat, lng: initialLng });
      map.setCenter({ lat: initialLat, lng: initialLng });
      setSelectedLocation({ lat: initialLat, lng: initialLng });
    }
  }, [initialLat, initialLng, map, marker]);

  const initializeMap = () => {
    if (mapRef.current && window.google) {
      const mapInstance = new window.google.maps.Map(mapRef.current, {
        center: { lat: initialLat, lng: initialLng },
        zoom: 13,
        mapTypeId: 'roadmap'
      });

      const markerInstance = new window.google.maps.Marker({
        position: { lat: initialLat, lng: initialLng },
        map: mapInstance,
        draggable: true,
        title: 'Selected Location'
      });

      // Handle map click
      mapInstance.addListener('click', (event) => {
        const lat = event.latLng.lat();
        const lng = event.latLng.lng();

        markerInstance.setPosition({ lat, lng });
        setSelectedLocation({ lat, lng });
        onLocationSelect(lat, lng);
      });

      // Handle marker drag
      markerInstance.addListener('dragend', (event) => {
        const lat = event.latLng.lat();
        const lng = event.latLng.lng();

        setSelectedLocation({ lat, lng });
        onLocationSelect(lat, lng);
      });

      setMap(mapInstance);
      setMarker(markerInstance);
    }
  };

  const handleQuickSelect = (lat, lng, cityName) => {
    if (map && marker) {
      marker.setPosition({ lat, lng });
      map.setCenter({ lat, lng });
      setSelectedLocation({ lat, lng });
      onLocationSelect(lat, lng);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.mapContainer}>
        <div ref={mapRef} style={styles.map}></div>
      </div>

      <div style={styles.info}>
        <p style={styles.instructions}>
          📍 Click on the map or drag the marker to select location
        </p>
        <div style={styles.coordinates}>
          <span>Selected: {selectedLocation.lat.toFixed(6)}, {selectedLocation.lng.toFixed(6)}</span>
        </div>
      </div>

      <div style={styles.presetLocations}>
        <h5>Quick Select Cities:</h5>
        <button 
          onClick={() => handleQuickSelect(27.7172, 85.3240, 'Kathmandu')}
          style={styles.presetBtn}
        >
          Kathmandu
        </button>
        <button 
          onClick={() => handleQuickSelect(28.2096, 83.9856, 'Pokhara')}
          style={styles.presetBtn}
        >
          Pokhara
        </button>
        <button 
          onClick={() => handleQuickSelect(26.4525, 87.2718, 'Biratnagar')}
          style={styles.presetBtn}
        >
          Biratnagar
        </button>
      </div>
    </div>
  );
};

const styles = {
  container: {
    marginBottom: '1rem'
  },
  mapContainer: {
    border: '2px solid #d1d5db',
    borderRadius: '8px',
    overflow: 'hidden',
    marginBottom: '1rem'
  },
  map: {
    width: '100%',
    height: '400px'
  },
  info: {
    backgroundColor: '#f3f4f6',
    padding: '1rem',
    borderRadius: '6px',
    marginBottom: '1rem'
  },
  instructions: {
    margin: '0 0 0.5rem 0',
    color: '#374151',
    fontSize: '0.9rem'
  },
  coordinates: {
    fontSize: '0.8rem',
    color: '#6b7280',
    fontFamily: 'monospace'
  },
  presetLocations: {
    textAlign: 'center'
  },
  presetBtn: {
    backgroundColor: '#3b82f6',
    color: 'white',
    border: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '4px',
    margin: '0 0.5rem',
    cursor: 'pointer',
    fontSize: '0.9rem'
  }
};

export default MapPicker;
